#include <string.h>

UART_HandleTypeDef huart;

void UART_Init(void) {
    huart.Instance = USART3;
    huart.Init.BaudRate = 57600;
    huart.Init.WordLength = UART_WORDLENGTH_8B;
    huart.Init.StopBits = UART_STOPBITS_1;
    huart.Init.Parity = UART_PARITY_NONE;
    huart.Init.Mode = UART_MODE_TX_RX;
    huart.Init.HwFlowCtl = UART_HWCONTROL_NONE;
    huart.Init.OverSampling = UART_OVERSAMPLING_16;
    HAL_UART_Init(&huart);
}

void UART_Transmit_String(const char* str) {
    HAL_UART_Transmit(&huart, (uint8_t*)str, strlen(str), 1000);
}

void UART_Transmit_Number(int number) {
    char buffer[16];
    sprintf(buffer, "%d\r\n", number);
    UART_Transmit_String(buffer);
}

HAL_StatusTypeDef UART_Receive_String(char* buffer, uint16_t size) {
    return HAL_UART_Receive(&huart, (uint8_t*)buffer, size, 1000);
}

void UART_Echo_Test(void) {
    char rx_buffer[100];

    UART_Transmit_String("Echo Test Started\r\n");

    while(1) {
        if(HAL_UART_Receive(&huart, (uint8_t*)rx_buffer, 1, 1000) == HAL_OK) {
            HAL_UART_Transmit(&huart, (uint8_t*)rx_buffer, 1, 1000);
        }
    }
}

