    char rx_buffer[100];

    UART_Transmit_String("Echo Test Started\r\n");

    while(1) {
        if(HAL_UART_Receive(&huart, (uint8_t*)rx_buffer, 1, 1000) == HAL_OK) {
            HAL_UART_Transmit(&huart, (uint8_t*)rx_buffer, 1, 1000);
        }
    }
}

