    for(uint16_t i = 0; i <= 1000; i += 10) {
        PWM_SetDutyCycle(i);
        HAL_Delay(20);
    }
    for(uint16_t i = 1000; i > 0; i -= 10) {
        PWM_SetDutyCycle(i);
        HAL_Delay(20);
    }
}

