void PWM_SetDutyCycle(uint16_t duty) {
    __HAL_TIM_SET_COMPARE(&htim, TIM_CHANNEL_4, duty);
}

void PWM_Fade(void) {
    for(uint16_t i = 0; i <= 1000; i += 10) {
        PWM_SetDutyCycle(i);
        HAL_Delay(20);
    }
    for(uint16_t i = 1000; i > 0; i -= 10) {
        PWM_SetDutyCycle(i);
        HAL_Delay(20);
    }
}

